mapper.sql:
WITH RECURSIVE period_params AS ( SELECT TO_CHAR(CASE WHEN #{billCd} = '30' THEN DATE_TRUNC('month', MAKE_DATE(CAST(#{year} AS INTEGER), CAST(#{month} AS INTEGER), 1))::date WHEN #{billCd} = '20' THEN ((MAKE_DATE(CAST(#{year} AS INTEGER), CAST(#{month} AS INTEGER), 1) - INTERVAL '1 month') + INTERVAL '20 day')::date END, 'YYYY-MM-DD') AS start_dt, TO_CHAR(CASE WHEN #{billCd} = '30' THEN (DATE_TRUNC('month', MAKE_DATE(CAST(#{year} AS INTEGER), CAST(#{month} AS INTEGER), 1)) + INTERVAL '1 month')::date WHEN #{billCd} = '20' THEN (MAKE_DATE(CAST(#{year} AS INTEGER), CAST(#{month} AS INTEGER), 1) + INTERVAL '20 day')::date END, 'YYYY-MM-DD') AS end_dt ), ultimate_parent_map AS ( SELECT company_id, excclc_company_id AS parent_id, excclc_company_id AS ultimate_id, 1 AS level FROM shipper WHERE del_yn = 'N' AND use_yn = 'Y' UNION ALL SELECT upm.company_id, s.excclc_company_id, s.excclc_company_id, upm.level + 1 FROM ultimate_parent_map upm INNER JOIN shipper s ON upm.ultimate_id = s.company_id WHERE s.del_yn = 'N' AND s.use_yn = 'Y' AND upm.ultimate_id != s.excclc_company_id AND upm.level < 4 ), final_parent_map AS MATERIALIZED ( SELECT company_id, ultimate_id FROM ( SELECT company_id, ultimate_id, ROW_NUMBER() OVER(PARTITION BY company_id ORDER BY level DESC) AS rn FROM ultimate_parent_map ) t WHERE rn = 1 ), transport_by_month AS ( /* SENDER 처리 */ SELECT tr.transport_id, tr.sender_company_id, tr.sender_company_nm, tr.sender_transport_shipper_cd, tr.charge_cd, tr.sender_region_cd, tr.sender_region_dtl_cd, tr.sender_manager_nm, tr.sender_address, tr.sender_tel_no, tr.sender_manager_tel_no, tr.sender_rmk, tr.receiver_company_id, tr.receiver_company_nm, tr.receiver_transport_shipper_cd, tr.receiver_region_cd, tr.receiver_region_dtl_cd, tr.receiver_address, tr.receiver_tel_no, tr.receiver_manager_tel_no, tr.receiver_manager_nm, tr.receiver_rmk, tr.shipment_operation_date AS tr_shipment_operation_date, trd.transport_dtl_id, trd.calculation_cd, trd.calculation_target_cd, trd.sender_receiver_cd, trd.waybill_no, trd.kind_cd, trd.untpc, trd.qty, trd.amount, trd.rmk, trd.shipment_operation_date AS trd_shipment_operation_date, CAST(fpm.ultimate_id AS INTEGER) AS boss_id FROM transport_dtl trd CROSS JOIN period_params pp INNER JOIN transport tr ON tr.transport_id = trd.transport_id AND tr.del_yn = 'N' INNER JOIN final_parent_map fpm ON fpm.company_id = tr.sender_company_id INNER JOIN shipper boss_sh ON boss_sh.company_id = fpm.ultimate_id AND boss_sh.bill_company_id = #{billCompanyId} AND boss_sh.bill_stdr_cd = #{billCd} AND boss_sh.del_yn = 'N' AND boss_sh.use_yn = 'Y' WHERE trd.del_yn = 'N' AND trd.calculation_target_cd = 'SENDER' AND trd.shipment_operation_date >= pp.start_dt AND trd.shipment_operation_date < pp.end_dt
UNION ALL
/* RECEIVER 처리 */ SELECT tr.transport_id, tr.sender_company_id, tr.sender_company_nm, tr.sender_transport_shipper_cd, tr.charge_cd, tr.sender_region_cd, tr.sender_region_dtl_cd, tr.sender_manager_nm, tr.sender_address, tr.sender_tel_no, tr.sender_manager_tel_no, tr.sender_rmk, tr.receiver_company_id, tr.receiver_company_nm, tr.receiver_transport_shipper_cd, tr.receiver_region_cd, tr.receiver_region_dtl_cd, tr.receiver_address, tr.receiver_tel_no, tr.receiver_manager_tel_no, tr.receiver_manager_nm, tr.receiver_rmk, tr.shipment_operation_date AS tr_shipment_operation_date, trd.transport_dtl_id, trd.calculation_cd, trd.calculation_target_cd, trd.sender_receiver_cd, trd.waybill_no, trd.kind_cd, trd.untpc, trd.qty, trd.amount, trd.rmk, trd.shipment_operation_date AS trd_shipment_operation_date, CAST(fpm.ultimate_id AS INTEGER) AS boss_id FROM transport_dtl trd CROSS JOIN period_params pp INNER JOIN transport tr ON tr.transport_id = trd.transport_id AND tr.del_yn = 'N' INNER JOIN final_parent_map fpm ON fpm.company_id = tr.receiver_company_id INNER JOIN shipper boss_sh ON boss_sh.company_id = fpm.ultimate_id AND boss_sh.bill_company_id = #{billCompanyId} AND boss_sh.bill_stdr_cd = #{billCd} AND boss_sh.del_yn = 'N' AND boss_sh.use_yn = 'Y' WHERE trd.del_yn = 'N' AND trd.calculation_target_cd = 'RECEIVER' AND trd.shipment_operation_date >= pp.start_dt AND trd.shipment_operation_date < pp.end_dt )

mapper.select:
/* existsBillData */
	SELECT EXISTS (
		SELECT 1
		FROM bill
		WHERE
			bill_company_id = #{billCompanyId}
			AND year = #{year}
			AND month = #{month}
			AND bill_cd = #{billCd}
			AND del_yn = 'N'
	)

SELECT bi.bill_id, bi.bill_company_id, bc.company_nm , bi.year, bi.month, bi.bill_cd , bi.tot_amount , bi.communication_fee, bi.communication_fee_vat , bi.untpc, bi.untpc_vat, bi.weight_untpc, bi.weight_untpc_vat , bi.reg_id, bi.reg_dt, bi.chg_id, bi.chg_dt, bi.del_yn FROM bill bi INNER JOIN bill_company bc ON bc.bill_company_id = bi.bill_company_id WHERE bi.del_yn = 'N'
AND bi.year = #{year}
AND bi.month = #{month}
ORDER BY bi.year DESC, bi.month DESC, bi.bill_cd::int DESC, bi.bill_company_id DESC

mapper.update:
UPDATE bill_history
SET del_yn = 'Y',
    chg_id = #{chgId},
    chg_dt = now()
WHERE company_id = #{companyId}
  AND year = #{year}
  AND month = #{month}
